add_action('wp_ajax_petshop_choice_search', function() {
    check_ajax_referer('petshop_choice_nonce', 'nonce');
    $term = sanitize_text_field($_GET['term'] ?? '');
    $gramatura = sanitize_text_field($_GET['gramatura'] ?? '');
    $filter = sanitize_text_field($_GET['filter'] ?? ''); // Mix/mono/be_grudu/jautrus
    $warehouse = sanitize_text_field($_GET['warehouse'] ?? ''); // '', 'vf', 'zb', 'av'
    $source_cat = sanitize_text_field($_GET['source_cat'] ?? ''); // v8: globalus pool ŠALTINIO kategorijos slug (pvz. konservai-sunims)
    $browse = (($_GET['browse'] ?? '') === '1'); // v13: rodyti visus tinkamus (be paieškos termino)
    if (!$browse && strlen($term) < 2) { wp_send_json([]); return; }

    $tax_query = array('relation' => 'AND');
    // v8: ŠALTINIO kategorija — riboja pool paiešką (kad katėms prekės nelįstų į šuns rinkinį)
    if ($source_cat) {
        $tax_query[] = array('taxonomy'=>'product_cat', 'field'=>'slug', 'terms'=>$source_cat);
    }
    if ($gramatura) {
        $tax_query[] = array('taxonomy'=>'pa_pakuotes_dydis', 'field'=>'name', 'terms'=>$gramatura.' g');
    }
    // Pool filtras pagal tipą
    if ($filter === 'mono') {
        $tax_query[] = array('taxonomy'=>'pa_monoprotein', 'field'=>'slug', 'terms'=>'taip');
    } elseif ($filter === 'be_grudu') {
        $tax_query[] = array('taxonomy'=>'pa_be_grudu', 'field'=>'slug', 'terms'=>'be-grudu');
    } elseif ($filter === 'jautrus') {
        $tax_query[] = array('taxonomy'=>'pa_speciali_mityba', 'field'=>'slug', 'terms'=>'jautriam-virskinimui');
    } elseif ($filter === 'hipo') {
        $tax_query[] = array('taxonomy'=>'pa_speciali_mityba', 'field'=>'slug', 'terms'=>'hipoalerginis');
    }

    // Sandėlio filtras (meta_query)
    $meta_query = array();
    if ($warehouse === 'vf') {
        $meta_query[] = array('key'=>'_vf_enabled', 'value'=>'yes');
    } elseif ($warehouse === 'zb') {
        $meta_query[] = array('key'=>'_zb_enabled', 'value'=>'yes');
    } elseif ($warehouse === 'av') {
        // AV (nuosavas/Legacy) = NEI VF NEI ZB dropship.
        // PASTABA: čia "likutis" (ne teigiamas žymuo) — saugu TIK admin paieškai (rankinis atrinkimas).
        // Fulfillment logikai reiktų teigiamo žymens — atskiras projektas.
        $meta_query['relation'] = 'AND';
        $meta_query[] = array('relation'=>'OR',
            array('key'=>'_vf_enabled', 'compare'=>'NOT EXISTS'),
            array('key'=>'_vf_enabled', 'value'=>'yes', 'compare'=>'!=')
        );
        $meta_query[] = array('relation'=>'OR',
            array('key'=>'_zb_enabled', 'compare'=>'NOT EXISTS'),
            array('key'=>'_zb_enabled', 'value'=>'yes', 'compare'=>'!=')
        );
    }

    $args = array(
        'post_type' => 'product',
        'post_status' => 'publish',
        'posts_per_page' => $browse ? 150 : 25,
        'tax_query' => array(array('taxonomy'=>'product_type','field'=>'slug','terms'=>array('simple'))),
    );
    if (strlen($term) >= 2) { $args['s'] = $term; }
    if ($browse) { $args['orderby'] = 'title'; $args['order'] = 'ASC'; }
    if (count($tax_query) > 1) {
        $args['tax_query'] = array_merge($args['tax_query'], array($tax_query));
    }
    if (!empty($meta_query)) {
        $args['meta_query'] = $meta_query;
    }

    $query = new WP_Query($args);
    $results = array();
    if ($query->have_posts()) {
        while ($query->have_posts()) {
            $query->the_post();
            $pid = get_the_ID();
            $p = wc_get_product($pid);
            if (!$p) continue;
            $img = wp_get_attachment_image_url($p->get_image_id(), 'thumbnail') ?: '';
            $cost = get_post_meta($pid, '_cost_price', true);
        if ($cost === '' || $cost === false || $cost === null) $cost = get_post_meta($pid, '_vf_cost', true); // v11: VF savikaina
        if ($cost === '' || $cost === false || $cost === null) $cost = get_post_meta($pid, '_zb_cost', true); // v11: ZB savikaina
            $gram_terms = wc_get_product_terms($pid, 'pa_pakuotes_dydis', array('fields'=>'names'));
            $results[] = array(
                'id' => $pid,
                'text' => $p->get_name(),
                'price' => (float) $p->get_price(),
                'cost' => $cost ? (float) $cost : null,
                'stock' => $p->get_stock_quantity(),
                'gramatura' => !empty($gram_terms) ? $gram_terms[0] : '',
                'image' => $img,
            );
        }
        wp_reset_postdata();
    }
    wp_send_json($results);
});

