add_action('wp_ajax_petshop_create_choice', function() {
    check_ajax_referer('petshop_choice_nonce', 'nonce');
    if (!current_user_can('manage_woocommerce')) { wp_send_json_error('Neturite teisių.'); return; }

    $data = json_decode(stripslashes($_POST['choice_data'] ?? ''), true);
    if (!$data) { wp_send_json_error('Neteisingi duomenys.'); return; }

    $title = sanitize_text_field($data['title'] ?? '');
    $sku = sanitize_text_field($data['sku'] ?? '');
    $category_slug = sanitize_text_field($data['category'] ?? '');
    $groups = $data['groups'] ?? array(); // {group_key: {label, filter, gramaturos: {gram: {pool:[ids], sizes:{size:price}}}}}
    $no_gram = !empty($data['no_gram']); // v12: skanėstų režimas be gramatūros

    $errors = array();
    if (empty($title)) $errors[] = 'Trūksta pavadinimo.';
    if (empty($sku)) $errors[] = 'Trūksta SKU.';
    if (empty($groups)) $errors[] = 'Pridėkite bent vieną grupę su gramatūra, pool ir kainomis.';
    if (wc_get_product_id_by_sku($sku)) $errors[] = 'SKU "'.$sku.'" jau egzistuoja.';

    $cat_term = get_term_by('slug', $category_slug, 'product_cat');
    if (!$cat_term) $errors[] = 'Kategorija "'.$category_slug.'" nerasta.';

    if (!empty($errors)) { wp_send_json_error(implode(' ', $errors)); return; }

    global $wpdb;
    $table = $wpdb->prefix . 'wc_mnm_child_items';
    $config = array(); // {group_key: {label, gramaturos: {gram: {size: {product_id, price}}}}}
    $created_hidden = array();

    try {
        // Pirma sukuriam tėvinį (reikia jo ID paslėptų meta susiejimui)
        $parent = new WC_Product_Simple();
        $parent->set_name($title);
        $parent->set_sku($sku);
        $parent->set_status('publish');
        $parent->set_catalog_visibility('visible');
        $parent->set_category_ids(array($cat_term->term_id));
        $parent->set_short_description(sanitize_textarea_field($data['short_description'] ?? ''));
        $image_id = intval($data['image_id'] ?? 0); // v9: pagrindinė nuotrauka
        if ($image_id > 0) $parent->set_image_id($image_id);
        $parent->save();
        $parent_id = $parent->get_id();

        // Kiekvienai GRUPEI × gramatūrai × dydžiui — paslėptas MnM produktas
        foreach ($groups as $gkey => $group_data) {
            $glabel = sanitize_text_field($group_data['label'] ?? $gkey);
            $gramaturos = $group_data['gramaturos'] ?? array();
            if (empty($gramaturos)) continue;
            $config[$gkey] = array('label' => $glabel, 'gramaturos' => array());

            foreach ($gramaturos as $gram => $gram_data) {
                $pool = $gram_data['pool'] ?? array();
                $sizes = $gram_data['sizes'] ?? array();
                if (empty($pool) || empty($sizes)) continue;
                $config[$gkey]['gramaturos'][$gram] = array();

                foreach ($sizes as $size => $price) {
                    $size = intval($size);
                    $price = floatval($price);
                    if ($size < 1 || $price <= 0) continue;
                    $hidden_sku = $sku . '-' . $gkey . '-' . $gram . '-' . $size;
                    $ex = wc_get_product_id_by_sku($hidden_sku);
                    if ($ex) wp_delete_post($ex, true);

                    $hp = new WC_Product_Mix_and_Match();
                    $hp->set_name($title . ' · ' . $glabel . ' · ' . $gram . 'g · ' . $size . ' vnt (paslėptas)');
                    $hp->set_sku($hidden_sku);
                    $hp->set_status('publish');
                    $hp->set_catalog_visibility('hidden');
                    $hp->set_price($price);
                    $hp->set_regular_price($price);
                    $hp->set_min_container_size($size);
                    $hp->set_max_container_size($size);
                    $hp->update_meta_data('_mnm_content_source', 'products');
                    $hp->update_meta_data('_mnm_per_product_pricing', 'no');
                    $hp->save();
                    $hid = $hp->get_id();
                    $created_hidden[] = $hid;

                    // Atgalinės nuorodos (kad redagavimas veiktų iškart)
                    update_post_meta($hid, '_petshop_choice_parent', $parent_id);
                    update_post_meta($hid, '_petshop_choice_group', $gkey);
                    update_post_meta($hid, '_petshop_choice_gram', $gram);
                    update_post_meta($hid, '_petshop_choice_size', $size);

                    $o = 0;
                    foreach ($pool as $cpid) {
                        $o++;
                        $wpdb->insert($table, array('product_id'=>intval($cpid),'container_id'=>$hid,'menu_order'=>$o), array('%d','%d','%d'));
                    }
                    $config[$gkey]['gramaturos'][$gram][$size] = array('product_id'=>$hid, 'price'=>$price);
                }
            }
        }

        // Ar sukurta bent viena grupė su turiniu?
        $has_content = false;
        foreach ($config as $g) { if (!empty($g['gramaturos'])) { $has_content = true; break; } }
        if (!$has_content) {
            wp_delete_post($parent_id, true);
            wp_send_json_error('Nepavyko sukurti nė vieno paslėpto produkto.');
            return;
        }

        // Tėvinio pradinė kaina = pirmos grupės pirmos gramatūros pirmo dydžio
        $first_gkey = array_key_first($config);
        $first_gram = array_key_first($config[$first_gkey]['gramaturos']);
        $first_size = array_key_first($config[$first_gkey]['gramaturos'][$first_gram]);
        $init_price = $config[$first_gkey]['gramaturos'][$first_gram][$first_size]['price'];
        $parent->set_price($init_price);
        $parent->set_regular_price($init_price);
        $parent->save();

        // v8 KRITINIS: wp_slash prieš update_post_meta. Be jo update_metadata->wp_unslash nuima
        // wp_json_encode \uXXXX escape'ų backslash'us ir sugadina LT raides (pvz. "Be grūdų" -> "Be gru016bdu0173").
        update_post_meta($parent_id, '_petshop_choice_config', wp_slash(wp_json_encode($config)));
        update_post_meta($parent_id, '_petshop_is_choice_bundle', 'yes');
        update_post_meta($parent_id, '_petshop_choice_version', '2'); // v2 = grupių modelis
        if ($no_gram) update_post_meta($parent_id, '_petshop_choice_no_gram', 'yes'); // v12: skanėstų režimas
        $group_label = sanitize_text_field($data['group_label'] ?? '');
        if ($group_label !== '') update_post_meta($parent_id, '_petshop_choice_group_label', $group_label); // v15

        wp_send_json_success(array(
            'parent_id' => $parent_id,
            'hidden_count' => count($created_hidden),
            'group_count' => count($config),
            'view_url' => get_permalink($parent_id),
            'edit_url' => admin_url('post.php?post='.$parent_id.'&action=edit'),
        ));

    } catch (Exception $e) {
        wp_send_json_error('Klaida: ' . $e->getMessage());
    }
});

