        // Grupių modelis:
        // groups = [{key, label, filter, gramaturos:[{gram, sizes:[{size,price}], pool:[{id,text,price,cost}]}]}]
        var groups = [];

        // Grupių presetai (label + siūlomas filtras) — v10: priklauso nuo Pool šaltinio
        var PRESETS_DOG = [
            {key:'mix', label:'Mix', filter:''},
            {key:'jautrus', label:'Jautriam virškinimui', filter:'jautrus'},
            {key:'hipo', label:'Hipoalerginis', filter:'hipo'},
            {key:'mono', label:'Monoproteinas', filter:'mono'},
            {key:'be_grudu', label:'Be grūdų', filter:'be_grudu'}
        ];
        var PRESETS_CAT = [
            {key:'mix', label:'Mix', filter:''},
            {key:'isrankioms', label:'Išrankioms', filter:''},
            {key:'kaciukams', label:'Kačiukams', filter:''}
        ];
        // v14: kramtalams/skanėstams šunims — dydžio grupės (customer-relevant + vertės koherencija)
        var PRESETS_CHEW_DOG = [
            {key:'mazas', label:'Mažam šuniui', filter:''},
            {key:'vidutinis', label:'Vidutiniam šuniui', filter:''},
            {key:'didelis', label:'Dideliam šuniui', filter:''}
        ];
        function currentPresets(){
            var el = document.getElementById('pcf-source-cat');
            var src = el ? el.value : '';
            if (/katems/.test(src)) return PRESETS_CAT;
            if (noGram) return PRESETS_CHEW_DOG; // be-gramatūros šunų rinkinys (skanėstai/kramtalai) → dydžio grupės; kitiems vardams „+ Kita…"
            return PRESETS_DOG;
        }
        var FILTER_LABELS = {'':'Visi', 'mono':'Monoproteinas', 'be_grudu':'Be grūdų', 'jautrus':'Jautriam virškinimui', 'hipo':'Hipoalerginis'};

        var noGram = false; // v12: skanėstų režimas be gramatūros
        var groupsContainer = document.getElementById('pcf-groups');
        var createBtn = document.getElementById('pcf-create');
        var statusEl = document.getElementById('pcf-status');
        var resultEl = document.getElementById('pcf-result');

        // === Pridėti grupę (v8: preset mygtukai, ne prompt) ===
        function slugifyKey(s){ return s.trim().toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,''); }
        function addGroup(key, label, filter){
            if (!key) { alert('Netinkamas grupės pavadinimas.'); return; }
            if (groups.some(function(g){return g.key===key;})) { alert('Tokia grupė jau yra.'); return; }
            // v15: pridėjus dydžio grupę — auto antraštė „Šuns dydis" (jei tuščia)
            if (['mazas','vidutinis','didelis'].indexOf(key) >= 0){
                var glEl = document.getElementById('pcf-group-label');
                if (glEl && !glEl.value.trim()) glEl.value = 'Šuns dydis';
            }
            groups.push({
                key: key,
                label: label,
                filter: filter || '',
                gramaturos: noGram
                    ? [{ gram:'std', sizes:[{size:5,price:0},{size:7,price:0},{size:10,price:0}], pool:[] }]
                    : [{ gram:'400', sizes:[{size:6,price:0},{size:12,price:0}], pool:[] }]
            });
            render();
        }
        function renderAddButtons(){
            var row = document.getElementById('pcf-add-group-row');
            row.innerHTML = '';
            var used = groups.map(function(g){return g.key;});
            currentPresets().forEach(function(p){
                if (used.indexOf(p.key) >= 0) return; // jau pridėta
                var b = document.createElement('button');
                b.type = 'button'; b.className = 'button button-secondary';
                b.textContent = '+ ' + p.label;
                b.onclick = function(){ addGroup(p.key, p.label, p.filter); };
                row.appendChild(b);
            });
            var kb = document.createElement('button');
            kb.type = 'button'; kb.className = 'button';
