                b.onclick = function(){ groups[parseInt(this.dataset.gp)].filter = this.dataset.filter; render(); };
            });
            // Grupės sandėlio filtras
            C.querySelectorAll('.pcf-gwh').forEach(function(b){
                b.onclick = function(){ groups[parseInt(this.dataset.gp)].warehouse = this.dataset.wh; render(); };
            });
            // Pridėti gramatūrą grupei
            C.querySelectorAll('.pcf-add-gram').forEach(function(b){
                b.onclick = function(){
                    var gp = parseInt(this.dataset.gp);
                    var gram = prompt('Gramatūra (tik skaičius, pvz. 400):', '');
                    if (!gram || !/^\d+$/.test(gram)) return;
                    if (groups[gp].gramaturos.some(function(x){return x.gram===gram;})) { alert('Tokia gramatūra grupėje jau yra.'); return; }
                    groups[gp].gramaturos.push({ gram:gram, sizes:[{size:6,price:0},{size:12,price:0}], pool:[] });
                    render();
                };
            });
            // Trinti gramatūrą
            C.querySelectorAll('.pcf-del-gram').forEach(function(b){
                b.onclick = function(){
                    var gp=parseInt(this.dataset.gp), gi=parseInt(this.dataset.gi);
                    if (groups[gp].gramaturos.length<=1) { alert('Grupėje turi likti bent viena gramatūra.'); return; }
                    groups[gp].gramaturos.splice(gi,1); render();
                };
            });
            // Dydžio qty/price
            C.querySelectorAll('.pcf-size-qty').forEach(function(inp){
                inp.onchange = function(){ groups[this.dataset.gp].gramaturos[this.dataset.gi].sizes[this.dataset.si].size = parseInt(this.value)||1; render(); };
            });
            C.querySelectorAll('.pcf-size-price').forEach(function(inp){
                inp.onchange = function(){ groups[this.dataset.gp].gramaturos[this.dataset.gi].sizes[this.dataset.si].price = parseFloat(this.value)||0; render(); };
            });
            C.querySelectorAll('.pcf-add-size').forEach(function(b){
                b.onclick = function(){ groups[this.dataset.gp].gramaturos[this.dataset.gi].sizes.push({size:15,price:0}); render(); };
            });
            C.querySelectorAll('.pcf-del-size').forEach(function(b){
                b.onclick = function(){ groups[this.dataset.gp].gramaturos[this.dataset.gi].sizes.splice(parseInt(this.dataset.si),1); render(); };
            });
            C.querySelectorAll('.pcf-del-pool').forEach(function(b){
                b.onclick = function(){ groups[this.dataset.gp].gramaturos[this.dataset.gi].pool.splice(parseInt(this.dataset.ci),1); render(); };
            });
            // Paieška + "Rodyti visus tinkamus" (grupės filtras + sandėlis)
            function runPoolSearch(gp, gi, term, browse, resultsBox, inp){
                var gram = noGram ? '' : groups[gp].gramaturos[gi].gram; // v13: be-gramatūros nesiunčia 'std'
                var filter = groups[gp].filter || '';
                var warehouse = groups[gp].warehouse || '';
                var sourceCat = document.getElementById('pcf-source-cat').value;
                var url = ajaxurl+'?action=petshop_choice_search&nonce='+nonce
                    +'&term='+encodeURIComponent(term)+'&gramatura='+encodeURIComponent(gram)
                    +'&filter='+encodeURIComponent(filter)+'&warehouse='+encodeURIComponent(warehouse)
                    +'&source_cat='+encodeURIComponent(sourceCat)+(browse?'&browse=1':'');
                resultsBox.innerHTML='<div style="padding:8px;color:#999;">Kraunama...</div>'; resultsBox.style.display='block';
                fetch(url).then(function(r){return r.json();}).then(function(data){
                    var poolArr = groups[gp].gramaturos[gi].pool;
                    var avail = data.filter(function(p){ return !poolArr.some(function(c){return c.id===p.id;}); });
                    resultsBox.innerHTML='';
                    if(!data.length){ resultsBox.innerHTML='<div style="padding:8px;color:#999;">Nerasta</div>'; resultsBox.style.display='block'; return; }
                    if(browse){
                        var bar=document.createElement('div');
                        bar.style.cssText='padding:8px 12px;position:sticky;top:0;background:#f0f6fc;border-bottom:1px solid #cfe2f3;display:flex;gap:10px;align-items:center;flex-wrap:wrap;';
                        bar.innerHTML='<label style="font-size:12px;"><input type="checkbox" class="pcf-chk-all"> Pažymėti visus</label>'
                            +'<button type="button" class="button button-primary pcf-add-checked" style="font-size:12px;height:auto;padding:2px 10px;">➕ Pridėti pažymėtus</button>'
                            +'<button type="button" class="button pcf-browse-close" style="font-size:12px;height:auto;padding:2px 10px;">✕ uždaryti</button>'
                            +'<span style="font-size:11px;color:#666;">('+avail.length+' tinkamų, dar nepridėtų)</span>';
                        resultsBox.appendChild(bar);
                    }
                    data.forEach(function(p){
                        var already = poolArr.some(function(c){return c.id===p.id;});
                        var div=document.createElement('div');
                        div.style.cssText='padding:6px 12px;border-bottom:1px solid #eee;'+(already?'opacity:0.45;':'');
                        var info='<div style="font-size:13px;">'+p.text+'</div><div style="font-size:11px;color:#666;">Kaina: '+p.price.toFixed(2)+'€ | Savikaina: '+(p.cost!==null?p.cost.toFixed(2)+'€':'nėra')+' | '+p.gramatura+'</div>';
                        if(browse){
                            div.style.display='flex'; div.style.alignItems='center'; div.style.gap='8px';
                            var cb = already ? '<span style="width:16px;text-align:center;color:#2a8;">✓</span>' : '<input type="checkbox" class="pcf-chk">';
                            div.innerHTML = cb + '<div style="flex:1;">'+info+'</div>' + (already?'<span style="font-size:11px;color:#2a8;">pridėta</span>':'<button type="button" class="button pcf-add-one" style="font-size:11px;height:auto;padding:1px 8px;">+</button>');
                            div._p = p; div._already = already;
                            if(!already){ div.querySelector('.pcf-add-one').onclick=function(){ poolArr.push(p); render(); }; }
                        } else {
                            div.style.cursor = already?'default':'pointer';
                            div.innerHTML = info;
                            if(!already){ div.onclick=function(){ poolArr.push(p); resultsBox.style.display='none'; if(inp) inp.value=''; render(); }; }
                        }
                        resultsBox.appendChild(div);
                    });
                    resultsBox.style.display='block';
                    if(browse){
                        var chkAll=resultsBox.querySelector('.pcf-chk-all');
                        if(chkAll) chkAll.onchange=function(){ var ck=this.checked; resultsBox.querySelectorAll('.pcf-chk').forEach(function(c){c.checked=ck;}); };
                        var closeBtn=resultsBox.querySelector('.pcf-browse-close');
                        if(closeBtn) closeBtn.onclick=function(){ resultsBox.style.display='none'; };
                        var addBtn=resultsBox.querySelector('.pcf-add-checked');
                        if(addBtn) addBtn.onclick=function(){
                            var added=0;
                            resultsBox.querySelectorAll('.pcf-chk:checked').forEach(function(c){
                                var row=c.parentNode; var p=row._p;
                                if(p && !poolArr.some(function(x){return x.id===p.id;})){ poolArr.push(p); added++; }
                            });
                            if(added){ render(); } else { alert('Nepažymėta nė vieno naujo.'); }
                        };
                    }
                });
            }
            C.querySelectorAll('.pcf-search').forEach(function(inp){
                var gp = parseInt(inp.dataset.gp), gi = parseInt(inp.dataset.gi);
                var resultsBox = C.querySelector('.pcf-search-results[data-gp="'+inp.dataset.gp+'"][data-gi="'+inp.dataset.gi+'"]');
                var timer;
                inp.oninput = function(){
                    clearTimeout(timer);
                    var val = this.value.trim();
                    if (val.length<2){ resultsBox.style.display='none'; return; }
                    timer = setTimeout(function(){ runPoolSearch(gp, gi, val, false, resultsBox, inp); }, 300);
                };
            });
            C.querySelectorAll('.pcf-browse').forEach(function(b){
                b.onclick = function(){
                    var gp=parseInt(this.dataset.gp), gi=parseInt(this.dataset.gi);
                    var resultsBox = C.querySelector('.pcf-search-results[data-gp="'+this.dataset.gp+'"][data-gi="'+this.dataset.gi+'"]');
                    runPoolSearch(gp, gi, '', true, resultsBox, null);
                };
            });
        }

