            var title = document.getElementById('pcf-title').value.trim();
            var sku = document.getElementById('pcf-sku').value.trim();
            // Bent viena grupė su bent viena gramatūra, kuri turi pool + bent vieną kainą
            var hasValid = groups.some(function(grp){
                return grp.gramaturos.some(function(g){ return g.pool.length>0 && g.sizes.some(function(s){return s.price>0;}); });
            });
            createBtn.disabled = !(title && sku && hasValid);
        }
        document.getElementById('pcf-title').oninput = updateCreateBtn;
        document.getElementById('pcf-sku').oninput = updateCreateBtn;

        createBtn.onclick = function(){
            createBtn.disabled = true;
            statusEl.textContent = 'Kuriama...'; statusEl.style.color='#666';
            var payload = {
                title: document.getElementById('pcf-title').value.trim(),
                sku: document.getElementById('pcf-sku').value.trim(),
                category: document.getElementById('pcf-category').value,
                short_description: document.getElementById('pcf-short-desc').value.trim(),
                image_id: document.getElementById('pcf-image-id').value || '',
                no_gram: noGram ? 1 : 0,
                group_label: (document.getElementById('pcf-group-label') ? document.getElementById('pcf-group-label').value.trim() : ''),
                groups: {}
            };
            groups.forEach(function(grp){
                var gramOut = {};
                grp.gramaturos.forEach(function(g){
                    var sizes = {};
                    g.sizes.forEach(function(s){ if(s.price>0) sizes[s.size]=s.price; });
                    if(Object.keys(sizes).length && g.pool.length){
                        gramOut[g.gram] = { pool: g.pool.map(function(c){return c.id;}), sizes: sizes };
                    }
                });
                if (Object.keys(gramOut).length){
                    payload.groups[grp.key] = { label: grp.label, filter: grp.filter||'', gramaturos: gramOut };
                }
            });
            if (!Object.keys(payload.groups).length){ statusEl.textContent='❌ Nėra pilnų grupių (reikia pool + kaina).'; statusEl.style.color='#c00'; createBtn.disabled=false; return; }

            var fd = new FormData();
            fd.append('action','petshop_create_choice');
            fd.append('nonce',nonce);
            fd.append('choice_data', JSON.stringify(payload));
            fetch(ajaxurl,{method:'POST',body:fd}).then(function(r){return r.json();}).then(function(res){
                if(res.success){
                    var d=res.data;
                    statusEl.textContent='';
                    resultEl.style.display='block';
                    resultEl.innerHTML='<h3 style="color:#2e7d32;margin-top:0;">✅ Susidėjimo rinkinys sukurtas!</h3>'
                        +'<p>Tėvinis ID: <strong>'+d.parent_id+'</strong> | Grupių: '+d.group_count+' | Paslėptų produktų: '+d.hidden_count+'</p>'
                        +'<p><a href="'+d.view_url+'" target="_blank" class="button">🔗 Peržiūrėti</a> <a href="'+d.edit_url+'" class="button">✏️ Redaguoti</a></p>';
                } else {
                    statusEl.textContent='❌ '+(res.data||'Klaida'); statusEl.style.color='#c00';
                    createBtn.disabled=false;
                }
            }).catch(function(e){ statusEl.textContent='❌ '+e.message; statusEl.style.color='#c00'; createBtn.disabled=false; });
        };
    })();
    </script>
    <?php
